fn main() { println!("Testing compression..."); let test_data = "MFRGG43FMVZXG5DFON2HE2LTMVZXG5DFON2HE2LTMFRGG43FMVZXG5DFON2HE2LTMVZXG5DFON2HE2LTMFRGG43FMVZXG5DFON2HE2LTMVZXG5DFON2HE2LTMFRGG43FMVZXG5DFON2HE2LTMVZXG5DFON2HE2LT"; match cli::string_compressor::StringCompressor::compress_hybrid(test_data) { Ok(compressed) => { println!("Original: {} bytes", test_data.len()); println!("Compressed: {} bytes", compressed.len()); println!("Compression ratio: {:.1}%", (1.0 - (compressed.len() as f64 / test_data.len() as f64)) * 100.0); println!("Compressed data: {}", compressed); }, Err(e) => println!("Error: {}", e) } }
